diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 28d7e1ce401e..98719386bbc6 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -779,6 +779,17 @@ static void computeKnownBitsFromICmpCond(const Value *V, ICmpInst *Cmp,
   }

   computeKnownBitsFromCmp(V, Pred, LHS, RHS, Known, SQ);
+  
+  // If LHS != RHS, then LHS | RHS cannot be zero.
+  // This is because if they differ, at least one bit position differs,
+  // meaning at least one of them has a 1 in that position.
+  if (Pred == ICmpInst::ICMP_NE) {
+    Value *X, *Y;
+    if (match(V, m_Or(m_Specific(LHS), m_Specific(RHS))) ||
+        match(V, m_Or(m_Specific(RHS), m_Specific(LHS)))) {
+      Known.makeNonZero();
+    }
+  }
 }

